80fdaff4-7b73-11f1-9bc3-ca3196b25ae3	{"pk": 5, "name": "admin"}	2026-07-09 08:52:24.076124+00	2	t	userstories.userstory:37	{}	{"ref": 37, "tags": [], "owner": 5, "points": {"1": 1, "2": 1, "3": 1, "4": 1}, "status": 7, "subject": "act2 自我修正：每日限額（terse spec）", "due_date": null, "swimlane": null, "from_task": null, "is_closed": false, "milestone": null, "tribe_gig": null, "from_issue": null, "is_blocked": false, "assigned_to": null, "attachments": [], "description": "## 故事（必填）\\n身為轉帳用戶，我想要每日累計限額檢查，以便控管風險。\\n\\n## 驗收提示\\n- 限額內允許\\n- 超過限額擋下\\n", "finish_date": "None", "blocked_note": "", "kanban_order": 1783587144044100, "sprint_order": 1783587144037981, "backlog_order": 1783587144037967, "assigned_users": [], "description_html": "<h2 id=\\"_1\\">故事（必填）</h2>\\n<p>身為轉帳用戶，我想要每日累計限額檢查，以便控管風險。</p>\\n<h2 id=\\"_2\\">驗收提示</h2>\\n<ul>\\n<li>限額內允許</li>\\n<li>超過限額擋下</li>\\n</ul>", "team_requirement": false, "blocked_note_html": "", "custom_attributes": [], "client_requirement": false}	{"users": {}}			\N	\N	f	\N	\N	1	{}
810a50ec-7b73-11f1-9bc3-ca3196b25ae3	{"pk": 5, "name": "admin"}	2026-07-09 08:52:24.158877+00	1	f	userstories.userstory:37	{"custom_attributes": [[], [{"id": 1, "name": "repo", "type": "text", "value": "bankapp"}]]}	\N	{"users": {}}			\N	\N	f	\N	\N	1	{"custom_attributes": {"new": [{"id": 1, "name": "repo", "type": "text", "value": "bankapp", "value_diff": "<ins style=\\"background:#e6ffe6;\\">bankapp</ins>"}], "changed": [], "deleted": []}}
